import { PrimaryStats } from './Stats';

export type EquipmentSlotType = 'MAIN_HAND' | 'OFF_HAND' | 'HEAD' | 'BODY' | 'HANDS' | 'FEET' | 'ACCESSORY';

export enum EquipmentRarity {
  COMMON = 'Common',
  UNCOMMON = 'Uncommon',
  RARE = 'Rare',
  EPIC = 'Epic',
  LEGENDARY = 'Legendary'
}

export enum EquipmentType {
  SWORD = 'Sword',
  AXE = 'Axe',
  MACE = 'Mace',
  STAFF = 'Staff',
  DAGGER = 'Dagger',
  HELMET = 'Helmet',
  CHESTPLATE = 'Chestplate',
  SHIELD = 'Shield',
  GLOVES = 'Gloves',
  BOOTS = 'Boots',
}

export interface EquipmentStats {
  physicalAttack: number;
  physicalDefense: number;
  magicalAttack: number;
  magicalDefense: number;
}

export interface SpecialAbility {
  id: string;
  name: string;
  description: string;
  value?: number;
}

export interface Equipment {
  id: string;
  recipeId?: string;
  name: string;
  type: EquipmentType;
  quality: number;
  rarity: EquipmentRarity;
  price: number;

  icon?: string;
  image?: string;
  description?: string;

  // 전투 스탯
  stats: EquipmentStats;

  // 미니게임 보너스 정보
  appliedBonus?: {
    stat: keyof EquipmentStats;
    value: number;
  };

  // 강화 시스템
  enhancementCount: number; // 5콤보마다 누적된 강화 횟수

  // 특수 능력
  specialAbilities: SpecialAbility[];

  // 내구도 시스템
  durability: number;      // 현재 내구도
  maxDurability: number;   // 최대 내구도
  isRepairable: boolean;   // 수리 가능 여부

  // 장착 가이드 (최소 스탯)
  equipRequirements?: Partial<PrimaryStats>;

  // 메타데이터
  craftedDate?: number;
  crafterName?: string;
  previousOwners?: string[]; 

  // 슬롯 정보
  slotType: EquipmentSlotType;
  isTwoHanded?: boolean;
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

export interface SmithingSceneData {
  onComplete: (score: number, enhancementCount: number) => void;
  onStatusUpdate?: (temp: number) => void;
  onHeatUpRequest?: () => void;
  difficulty: number;
  initialTemp: number;
  charcoalCount: number | string;
}

interface Point {
  x: number;
  y: number;
}

type SmithingTool = 'HAMMER' | 'TONGS';

export default class SmithingScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public events!: Phaser.Events.EventEmitter;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public anims!: Phaser.Animations.AnimationManager;

  private backgroundTile!: Phaser.GameObjects.TileSprite;
  private bgOverlay!: Phaser.GameObjects.Rectangle;
  private anvilImage!: Phaser.GameObjects.Image;

  private targetRing!: Phaser.GameObjects.Graphics;
  private approachRing!: Phaser.GameObjects.Graphics;
  private targetOutlineGraphics!: Phaser.GameObjects.Graphics;

  private progressBar!: Phaser.GameObjects.Graphics;
  private progBg!: Phaser.GameObjects.Graphics;
  private comboText!: Phaser.GameObjects.Text;
  private infoText!: Phaser.GameObjects.Text;
  private qualityText!: Phaser.GameObjects.Text;

  private ambientGlow!: Phaser.GameObjects.Arc;
  private flashOverlay!: Phaser.GameObjects.Rectangle;

  private billetContainer!: Phaser.GameObjects.Container;
  private billetImage?: Phaser.GameObjects.Image;
  private manualControlsContainer!: Phaser.GameObjects.Container;

  private toolSwitcherContainer!: Phaser.GameObjects.Container;
  private hammerBtn!: Phaser.GameObjects.Container;
  private tongsBtn!: Phaser.GameObjects.Container;
  private currentTool: SmithingTool = 'HAMMER';

  private isRotatingManual = false;
  private isMovingManualX = false;
  private isMovingManualY = false;
  private startPointerPos = { x: 0, y: 0 };
  private startBilletPos = { x: 0, y: 0 };
  private startPointerAngle = 0;
  private startBilletRotation = 0;
  private isSnapped = false;
  private snapTween?: Phaser.Tweens.Tween;

  private hitPoly!: Phaser.Geom.Polygon;
  private spawnPoly!: Phaser.Geom.Polygon; 
  private outlineCache: Map<string, Point[]> = new Map();

  private centerX = 0;
  private centerY = 0;
  private hitX = 0;
  private hitY = 0;

  private viewW = 0;
  private viewH = 0;

  private score = 0;
  private targetScore = 100;
  private combo = 0;
  private lastHitTime = 0;
  private hitCooldown = 200;
  private isFinished = false;
  private isPlaying = false;
  private isReadyToStart = false;

  private currentQuality = 100;
  private perfectCount = 0;
  private enhancementCount = 0; // 5콤보마다 증가하는 강화 횟수
  private pinnedTexts: Phaser.GameObjects.Text[] = [];

  private temperature = 0;
  private coolingRate = 2;
  private currentTempStage: 'COLD' | 'AURA' | 'HOT' | 'WARM' | 'NORMAL' = 'COLD';
  private charcoalCount: number | string = 0;

  private startRadius = 180;
  private targetRadius = 45;
  private currentRadius = 180;
  private shrinkDuration = 2000;
  private ringTimer = 0;

  private currentTargetColor = 0xfabf24;
  private currentSpeedMult = 1.0;

  private readonly UI_PAD_TOP = 18;
  private readonly UI_PAD_SIDE = 16; 
  private readonly UI_PAD_BOTTOM = 28;
  private readonly UI_GAP = 18;

  private readonly TEMP_GAUGE_H_MIN = 80;

  private tempBarGraphics!: Phaser.GameObjects.Graphics;
  private tempBgGraphics!: Phaser.GameObjects.Graphics;
  private tempValueText!: Phaser.GameObjects.Text;

  private bellowsContainer!: Phaser.GameObjects.Container;
  private bellowsSprite!: Phaser.GameObjects.Sprite;
  private bellowsBg!: Phaser.GameObjects.Arc;

  private heatUpBtnContainer!: Phaser.GameObjects.Container;
  private uiContainer!: Phaser.GameObjects.Container;
  private isPumping = false;

  private onComplete?: (score: number, enhancementCount: number) => void;
  private onStatusUpdate?: (temp: number) => void;
  private onHeatUpRequest?: () => void;

  private root!: Phaser.GameObjects.Container;

  private isPortrait = false;
  private lastPortrait?: boolean;
  private isRelayouting = false;

  private readonly BILLET_W_ON_ANVIL = 0.80; 
  private readonly BILLET_ANGLE_DEG = -12;

  private readonly SNAP_DIST_THRESHOLD = 25;
  private readonly SNAP_ANGLE_THRESHOLD = Phaser.Math.DegToRad(6);

  private readonly ANVIL_ORIGINAL_W = 1024;
  private readonly ANVIL_ORIGINAL_H = 559;
  private readonly ANVIL_HIT_X = 630;
  private readonly ANVIL_HIT_Y = 140;

  constructor() {
    super('SmithingScene');
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK';
    if (q >= 100) return 'PRISTINE';
    if (q >= 90) return 'SUPERIOR';
    if (q >= 80) return 'FINE';
    if (q >= 70) return 'STANDARD';
    if (q >= 60) return 'RUSTIC';
    return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b';
    if (q >= 100) return '#fbbf24';
    if (q >= 90) return '#10b981';
    if (q >= 80) return '#3b82f6';
    if (q >= 70) return '#a8a29e';
    if (q >= 60) return '#d97706';
    return '#ef4444';
  }

  init(data: SmithingSceneData) {
    this.onComplete = data.onComplete;
    this.onStatusUpdate = data.onStatusUpdate;
    this.onHeatUpRequest = data.onHeatUpRequest;
    this.charcoalCount = data.charcoalCount;
    this.shrinkDuration = Math.max(800, 2000 - data.difficulty * 200);
    this.coolingRate = 2 + data.difficulty * 0.8;
    this.score = 0;
    this.combo = 0;
    this.enhancementCount = 0;
    this.pinnedTexts = [];
    this.temperature = data.initialTemp || 0;
    this.isFinished = false;
    this.isPlaying = false;
    this.isReadyToStart = this.temperature > 0;
    this.currentQuality = 100;
    this.perfectCount = 0;
    this.outlineCache.clear();
    this.currentTool = 'HAMMER';
    this.isSnapped = true;
  }

  preload() {
    this.load.image('tile_forge', getAssetUrl('tile_forge.png'));
    this.load.image('anvil_img', getAssetUrl('anvil.png'));
    this.load.image('spark_perfect', getAssetUrl('particle_spark1.png'));
    this.load.image('spark_normal', getAssetUrl('particle_spark2.png'));
    this.load.image('billet_stage_0', getAssetUrl('billet_default.png'));
    this.load.image('blade_stage_1', getAssetUrl('billet_blade_01.png'));
    this.load.image('blade_stage_2', getAssetUrl('billet_blade_02.png'));
    this.load.image('blade_stage_3', getAssetUrl('billet_blade_03.png'));
    this.load.image('blade_stage_4', getAssetUrl('billet_blade_04.png'));
    this.load.image('blade_stage_5', getAssetUrl('billet_blade_05.png'));
    this.load.spritesheet('bellows', getAssetUrl('bellows_sprite.png'), { frameWidth: 298, frameHeight: 188 });
    this.load.image('icon_hammer', getAssetUrl('hammer.png'));
    this.load.image('icon_tongs', getAssetUrl('tongs.png'));
  }

  create() {
    if (this.scale.width <= 0 || this.scale.height <= 0) return;
    this.root = this.add.container(0, 0);
    if (!this.anims.exists('bellows_pump')) {
      this.anims.create({
        key: 'bellows_pump',
        frames: [0, 1, 2, 3, 4, 5, 6, 7].map((i) => ({ key: 'bellows', frame: i })),
        frameRate: 18,
        repeat: 0,
      });
    }
    this.backgroundTile = this.add.tileSprite(0, 0, 1280, 720, 'tile_forge').setOrigin(0).setDepth(-2).setAlpha(0.7);
    this.root.add(this.backgroundTile);
    this.bgOverlay = this.add.rectangle(0, 0, 1280, 720, 0x000000, 0.4).setOrigin(0).setDepth(-1);
    this.root.add(this.bgOverlay);
    this.anvilImage = this.add.image(0, 0, 'anvil_img').setDepth(1).setOrigin(0.5, 0.5);
    this.root.add(this.anvilImage);

    this.targetOutlineGraphics = this.add.graphics().setDepth(2).setAlpha(0.6);
    this.root.add(this.targetOutlineGraphics);

    this.billetContainer = this.add.container(0, 0).setDepth(3).setAngle(this.BILLET_ANGLE_DEG);

    if (this.textures.exists('billet_stage_0')) {
      this.billetImage = this.add.image(0, 0, 'billet_stage_0').setOrigin(0.5);
      this.billetContainer.add(this.billetImage);
    }
    this.root.add(this.billetContainer);

    this.targetRing = this.add.graphics().setDepth(5);
    this.approachRing = this.add.graphics().setDepth(5);
    this.root.add([this.targetRing, this.approachRing]);
    this.uiContainer = this.add.container(0, 0).setDepth(20);
    this.root.add(this.uiContainer);
    this.ambientGlow = this.add.circle(0, 0, 500, 0xea580c, 0).setFillStyle(0xea580c, 0.25).setDepth(0);
    this.root.add(this.ambientGlow);
    this.flashOverlay = this.add.rectangle(0, 0, 1280, 720, 0xffaa00, 0).setOrigin(0).setDepth(100);
    this.root.add(this.flashOverlay);

    this.setupUI();
    this.setupManualControls();
    this.setupToolSwitcher();

    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);
    this.events.once(Phaser.Scenes.Events.SHUTDOWN, () => {
      this.scale.off('resize', this.handleResize, this);
    });
    this.time.delayedCall(80, () => this.handleResize());

    this.setBilletStage(0);

    this.input.on('pointerdown', (pointer: Phaser.Input.Pointer, objs: any[]) => {
        const x = pointer.x; const y = pointer.y;

        const isBellowsClick = this.isBellowsClick(objs);
        const isHeatUpClick = this.isHeatUpClick(objs);
        const isSwitcherClick = objs.some(obj => obj.parentContainer === this.toolSwitcherContainer || obj === this.toolSwitcherContainer);

        if (isBellowsClick) { this.pumpBellows(); return; }
        if (isHeatUpClick) { this.requestHeatUp(); return; }
        if (isSwitcherClick) return;

        if (!this.isPlaying) { this.handleStartTap(x, y); return; }

        if (this.currentTool === 'HAMMER') {
          if (this.isPointerInHitArea(x, y)) {
            this.handleHammerSwing(x, y);
          } else { 
            const isOnAnvil = this.anvilImage.getBounds().contains(x, y);
            this.handleMiss(x, y, isOnAnvil ? 'STRUCK ANVIL' : 'MISS'); 
          }
        }
      }, this
    );

    this.input.on('pointermove', (pointer: Phaser.Input.Pointer) => {
        if (this.isSnapped) return;

        if (this.isRotatingManual) {
            const currentAngle = Phaser.Math.Angle.Between(this.billetContainer.x, this.billetContainer.y, pointer.x, pointer.y);
            const delta = currentAngle - this.startPointerAngle;
            this.billetContainer.rotation = this.startBilletRotation + delta;
            this.checkMagnetSnap();
        } 
        else if (this.isMovingManualX) {
            const dx = pointer.x - this.startPointerPos.x;
            this.billetContainer.x = this.startBilletPos.x + dx;
            this.checkMagnetSnap();
        }
        else if (this.isMovingManualY) {
            const dy = pointer.y - this.startPointerPos.y;
            this.billetContainer.y = this.startBilletPos.y + dy;
            this.checkMagnetSnap();
        }

        if (this.isRotatingManual || this.isMovingManualX || this.isMovingManualY) {
            this.rebuildHitPoly();
            if (this.currentTool === 'TONGS') {
                this.drawTargetGuidelineFixed();
            }
        }
    });

    this.input.on('pointerup', () => {
        this.isRotatingManual = false;
        this.isMovingManualX = false;
        this.isMovingManualY = false;
    });

    this.switchTool('HAMMER');
  }

  private setupToolSwitcher() {
    this.toolSwitcherContainer = this.add.container(0, 0).setDepth(30);
    this.root.add(this.toolSwitcherContainer);

    const createToolBtn = (x: number, y: number, key: string, tool: SmithingTool) => {
        const size = 110; 
        const bg = this.add.circle(0, 0, size/2, 0x1c1917, 0.9).setStrokeStyle(5, 0x57534e).setInteractive({ useHandCursor: true });
        const icon = this.add.image(0, 0, key).setDisplaySize(size * 0.65, size * 0.65);
        const container = this.add.container(x, y, [bg, icon]);

        bg.on('pointerdown', (p: any, lx: any, ly: any, event: any) => {
            event.stopPropagation();
            if (this.currentTool === tool && tool === 'HAMMER') {
                this.resetRing(); 
            } else {
                this.switchTool(tool);
            }
            this.tweens.add({ targets: container, scale: 0.85, duration: 80, yoyo: true });
        });

        return container;
    };

    this.hammerBtn = createToolBtn(0, 0, 'icon_hammer', 'HAMMER');
    this.tongsBtn = createToolBtn(125, 0, 'icon_tongs', 'TONGS'); 
    this.toolSwitcherContainer.add([this.hammerBtn, this.tongsBtn]);
  }

  private switchTool(tool: SmithingTool) {
    this.currentTool = tool;

    const hamBg = this.hammerBtn.list[0] as Phaser.GameObjects.Arc;
    const tonBg = this.tongsBtn.list[0] as Phaser.GameObjects.Arc;

    if (tool === 'HAMMER') {
        hamBg.setStrokeStyle(6, 0xfbbf24);
        hamBg.setFillStyle(0x451a03, 1);
        tonBg.setStrokeStyle(4, 0x57534e);
        tonBg.setFillStyle(0x1c1917, 0.9);

        if (this.manualControlsContainer) this.manualControlsContainer.setVisible(false);
        this.targetRing.setVisible(this.isPlaying);
        this.approachRing.setVisible(this.isPlaying);
        if (this.isPlaying) this.resetRing();
        this.targetOutlineGraphics.setVisible(false);
    } else {
        tonBg.setStrokeStyle(6, 0xfbbf24);
        tonBg.setFillStyle(0x451a03, 1);
        hamBg.setStrokeStyle(4, 0x57534e);
        hamBg.setFillStyle(0x1c1917, 0.9);

        if (this.manualControlsContainer) this.manualControlsContainer.setVisible(true);
        this.targetRing.setVisible(false);
        this.approachRing.setVisible(false);
        this.targetOutlineGraphics.setVisible(true);
        this.drawTargetGuidelineFixed();
    }
  }

  private setupManualControls() {
    this.manualControlsContainer = this.add.container(0, 0).setDepth(10);
    this.billetContainer.add(this.manualControlsContainer);

    const createBtn = (x: number, y: number, label: string, mode: 'X' | 'Y' | 'ROT') => {
        const size = 52;
        const isRot = mode === 'ROT';
        const bg = this.add.circle(0, 0, size/2, 0x1c1917, 0.8)
            .setStrokeStyle(2, isRot ? 0x3b82f6 : 0xfbbf24, 0.8)
            .setInteractive({ useHandCursor: true });

        const txt = this.add.text(0, 0, label, { fontSize: '24px', color: isRot ? '#60a5fa' : '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
        const btn = this.add.container(x, y, [bg, txt]);

        bg.on('pointerdown', (p: Phaser.Input.Pointer, lx: any, ly: any, event: any) => {
            event.stopPropagation();
            if (this.isSnapped) this.isSnapped = false;

            this.startPointerPos = { x: p.x, y: p.y };
            this.startBilletPos = { x: this.billetContainer.x, y: this.billetContainer.y };

            if (isRot) {
                this.isRotatingManual = true;
                this.startPointerAngle = Phaser.Math.Angle.Between(this.billetContainer.x, this.billetContainer.y, p.x, p.y);
                this.startBilletRotation = this.billetContainer.rotation;
            } else if (mode === 'X') {
                this.isMovingManualX = true;
            } else if (mode === 'Y') {
                this.isMovingManualY = true;
            }

            this.tweens.add({ targets: btn, scale: 0.8, duration: 100 });
        });

        bg.on('pointerup', () => {
            this.tweens.add({ targets: btn, scale: 1, duration: 100 });
        });

        return btn;
    };

    const offsetX = 280;
    const offsetY = 120;

    const btnL = createBtn(-offsetX, 0, '←', 'X');
    const btnR = createBtn(offsetX, 0, '→', 'X');
    const btnU = createBtn(0, -offsetY, '↑', 'Y');
    const btnD = createBtn(0, offsetY, '↓', 'Y');

    const btnRotTL = createBtn(-offsetX, -offsetY, '🔄', 'ROT');
    const btnRotBR = createBtn(offsetX, offsetY, '🔄', 'ROT');

    this.manualControlsContainer.add([btnL, btnR, btnU, btnD, btnRotTL, btnRotBR]);
    this.manualControlsContainer.setVisible(false);
  }

  private checkMagnetSnap() {
    if (this.currentTool !== 'TONGS') return;
    if (this.isSnapped || (this.snapTween && this.snapTween.isPlaying())) return;

    const anvilScale = this.anvilImage.scaleX;
    const offsetX = (this.ANVIL_HIT_X - this.ANVIL_ORIGINAL_W / 2) * anvilScale;
    const offsetY = (this.ANVIL_HIT_Y - this.ANVIL_ORIGINAL_H / 2) * anvilScale;
    const targetX = this.anvilImage.x + offsetX;
    const targetY = this.anvilImage.y + offsetY;
    const targetRot = Phaser.Math.DegToRad(this.BILLET_ANGLE_DEG);

    const dist = Phaser.Math.Distance.Between(this.billetContainer.x, this.billetContainer.y, targetX, targetY);
    const angleDiff = Math.abs(Phaser.Math.Angle.ShortestBetween(this.billetContainer.rotation, targetRot));

    if (dist < this.SNAP_DIST_THRESHOLD && angleDiff < this.SNAP_ANGLE_THRESHOLD) {
        this.isSnapped = true;

        this.isRotatingManual = false;
        this.isMovingManualX = false;
        this.isMovingManualY = false;

        this.snapTween = this.tweens.add({
            targets: this.billetContainer,
            x: targetX,
            y: targetY,
            rotation: targetRot,
            duration: 150,
            ease: 'Back.easeOut',
            onComplete: () => {
                this.rebuildHitPoly();
                this.drawTargetGuidelineFixed();
                this.createSparks(25, 0x10b981, 1.4, 'spark_perfect', targetX, targetY);
            }
        });
    }
  }

  private applyKickback(intensity: number) {
      if (!this.billetContainer) return;
      this.isSnapped = false;
      const posRange = intensity * 15;
      const angleRange = intensity * 8;
      const dx = Phaser.Math.FloatBetween(-posRange, posRange);
      const dy = Phaser.Math.FloatBetween(-posRange, posRange);
      const da = Phaser.Math.FloatBetween(-angleRange, angleRange);

      this.tweens.add({ 
        targets: this.billetContainer, 
        x: this.billetContainer.x + dx, 
        y: this.billetContainer.y + dy, 
        angle: this.billetContainer.angle + da, 
        duration: 150, 
        ease: 'Cubic.easeOut', 
        onUpdate: () => this.rebuildHitPoly() 
      });
  }

  private isBellowsClick(objs: any[]) { return objs.includes(this.bellowsContainer) || this.bellowsContainer.list.some((c) => objs.includes(c)); }
  private isHeatUpClick(objs: any[]) { return objs.includes(this.heatUpBtnContainer) || this.heatUpBtnContainer.list.some((c) => objs.includes(c)); }

  private setupUI() {
    this.progBg = this.add.graphics();
    this.progressBar = this.add.graphics();
    this.qualityText = this.add.text(0, 55, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '18px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([this.progBg, this.progressBar, this.qualityText]);

    this.tempBgGraphics = this.add.graphics();
    this.tempBarGraphics = this.add.graphics();
    this.tempValueText = this.add.text(0, 0, '20°C', { fontFamily: 'Grenze', fontSize: '14px', color: '#fff', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([this.tempBgGraphics, this.tempBarGraphics, this.tempValueText]);

    const r = 48; 

    this.bellowsContainer = this.add.container(0, 0);
    this.bellowsBg = this.add.circle(0, 0, r, 0x1c1917, 1).setStrokeStyle(3, 0x10b981).setName('btnBg');
    this.bellowsSprite = this.add.sprite(0, 0, 'bellows').setScale(0.28); 
    const pumpTxt = this.add.text(0, 30, 'PUMP', { fontSize: '12px', color: '#fde68a', fontFamily: 'Grenze', fontStyle: 'bold' }).setOrigin(0.5);
    this.bellowsContainer.add([this.bellowsBg, this.bellowsSprite, pumpTxt]).setInteractive(new Phaser.Geom.Circle(0, 0, r), Phaser.Geom.Circle.Contains);
    this.bellowsSprite.on('animationcomplete-bellows_pump', () => { this.isPumping = false; });

    this.heatUpBtnContainer = this.add.container(0, 0);
    const btnBg = this.add.circle(0, 0, r, 0x1c1917, 1).setStrokeStyle(3, 0x57534e).setName('btnBg');
    const btnIcon = this.add.text(0, -10, '🔥', { fontSize: '24px' }).setOrigin(0.5).setName('btnIcon');
    const btnLabel = this.add.text(0, 10, 'HEAT', { fontSize: '12px', color: '#fbbf24', fontStyle: 'bold', fontFamily: 'Grenze' }).setOrigin(0.5);
    const countTxt = this.add.text(0, 30, `x${this.charcoalCount}`, { fontSize: '12px', color: '#78716c', fontFamily: 'Grenze' }).setOrigin(0.5).setName('countTxt');
    this.heatUpBtnContainer.add([btnBg, btnIcon, btnLabel, countTxt]).setInteractive(new Phaser.Geom.Circle(0, 0, r), Phaser.Geom.Circle.Contains);

    this.uiContainer.add([this.bellowsContainer, this.heatUpBtnContainer]);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '36px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(26);
    this.infoText = this.add.text(0, 0, this.isReadyToStart ? 'TOUCH TO START' : 'FORGE IS COLD\nADD FUEL', {
        fontFamily: 'Grenze Gotisch', fontSize: '24px', color: this.isReadyToStart ? '#fbbf24' : '#3b82f6', align: 'center', stroke: '#000', strokeThickness: 5,
      }).setOrigin(0.5);
    this.uiContainer.add([this.comboText, this.infoText]);
    this.tweens.add({ targets: this.infoText, alpha: 0.5, yoyo: true, repeat: -1, duration: 800 });
  }

  private generateOutlinePoints(key: string): Point[] {
    if (this.outlineCache.has(key)) return this.outlineCache.get(key)!;
    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return [];
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return [];
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified: Point[] = [];
    const step = Math.max(1, Math.floor(path.length / 50));
    for (let i = 0; i < path.length; i += step) { simplified.push({ x: path[i].x - w/2, y: path[i].y - h/2 }); }
    this.outlineCache.set(key, simplified);
    return simplified;
  }

  private drawTargetGuidelineFixed() {
    if (!this.targetOutlineGraphics || !this.billetImage) return;
    this.targetOutlineGraphics.clear();
    const currentKey = this.billetImage.texture.key;
    const localPoints = this.generateOutlinePoints(currentKey);
    const rad = Phaser.Math.DegToRad(this.BILLET_ANGLE_DEG);
    const cos = Math.cos(rad); const sin = Math.sin(rad);
    const scale = this.billetContainer.scaleX;
    const anvilScale = this.anvilImage.scaleX;
    const offsetX = (this.ANVIL_HIT_X - this.ANVIL_ORIGINAL_W / 2) * anvilScale;
    const offsetY = (this.ANVIL_HIT_Y - this.ANVIL_ORIGINAL_H / 2) * anvilScale;
    const targetX = this.anvilImage.x + offsetX;
    const targetY = this.anvilImage.y + offsetY;
    const transformed = localPoints.map(p => ({ x: targetX + (p.x * scale * cos - p.y * scale * sin), y: targetY + (p.x * scale * sin + p.y * scale * cos) }));
    this.targetOutlineGraphics.lineStyle(2, this.isSnapped ? 0x10b981 : 0xfbbf24, this.isSnapped ? 0.8 : 0.4);
    const dashLen = 8; const gapLen = 5;
    for (let i = 0; i < transformed.length; i++) {
        const p1 = transformed[i]; const p2 = transformed[(i + 1) % transformed.length];
        const dist = Phaser.Math.Distance.Between(p1.x, p1.y, p2.x, p2.y);
        const angle = Phaser.Math.Angle.Between(p1.x, p1.y, p2.x, p2.y);
        let curDist = 0; let draw = true;
        while (curDist < dist) {
            const step = draw ? dashLen : gapLen; const nextDist = Math.min(curDist + step, dist);
            if (draw) this.targetOutlineGraphics.lineBetween(p1.x + Math.cos(angle) * curDist, p1.y + Math.sin(angle) * curDist, start.x + Math.cos(angle) * nextDist, p1.y + Math.sin(angle) * nextDist);
            curDist = nextDist; draw = !draw;
        }
    }
  }

  private placeBilletOnAnvil() {
    if (!this.anvilImage || !this.billetContainer) return;
    const currentKey = this.billetImage?.texture?.key ?? 'billet_stage_0'; 
    const tex = this.textures.get(currentKey);
    const src = tex?.getSourceImage() as HTMLImageElement | HTMLCanvasElement | undefined;
    const baseTexW = src?.width ?? 1220;
    const targetBilletW = this.anvilImage.displayWidth * this.BILLET_W_ON_ANVIL; 
    const ratio = targetBilletW / baseTexW;
    const billetScale = Phaser.Math.Clamp(ratio, 0.15, 2.0);

    const anvilScale = this.anvilImage.scaleX;
    const offsetX = (this.ANVIL_HIT_X - this.ANVIL_ORIGINAL_W / 2) * anvilScale;
    const offsetY = (this.ANVIL_HIT_Y - this.ANVIL_ORIGINAL_H / 2) * anvilScale;

    const targetX = this.anvilImage.x + offsetX;
    const targetY = this.anvilImage.y + offsetY;

    if (!this.isPlaying || (this.currentTool === 'HAMMER' && !this.isRotatingManual && !this.isMovingManualX && !this.isMovingManualY)) {
        this.billetContainer
            .setRotation(Phaser.Math.DegToRad(this.BILLET_ANGLE_DEG))
            .setScale(billetScale)
            .setPosition(targetX, targetY);
        this.isSnapped = true;
    }

    this.rebuildHitPoly();
    if (this.currentTool === 'TONGS') {
        this.drawTargetGuidelineFixed();
    }
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.gameSize.width; const h = gameSize?.height ?? this.scale.gameSize.height;
    if (w <= 0 || h <= 0) return;
    const nextPortrait = h > w; this.cameras.main.setViewport(0, 0, w, h);
    if (this.root) { this.root.setRotation(0); this.root.setPosition(0, 0); }
    const apply = (sw: number, sh: number, portrait: boolean) => {
      this.viewW = sw; this.viewH = sh; this.centerX = sw / 2; this.centerY = sh / 2;
      if (this.backgroundTile) this.backgroundTile.setSize(sw, sh);
      if (this.bgOverlay) this.bgOverlay.setSize(sw, sh);
      if (this.flashOverlay) this.flashOverlay.setSize(sw, sh);

      const anvilW = sw * 1.2; 
      const anvilScale = anvilW / this.anvilImage.width;
      const forgeCenterX = sw * 0.4;
      this.anvilImage.setScale(anvilScale).setPosition(forgeCenterX, this.centerY);

      if (this.ambientGlow) this.ambientGlow.setPosition(forgeCenterX, this.centerY);
      this.placeBilletOnAnvil();

      const basis = Math.min(sw, sh); 
      this.startRadius = Phaser.Math.Clamp(basis * (portrait ? 0.28 : 0.35), 105, 240);

      const isCompact = sh < 500; 
      this.repositionUI(sw, sh, portrait, isCompact);
      if (this.isPlaying && this.currentTool === 'HAMMER') this.resetRing();

      if (this.manualControlsContainer) {
          const invScale = 1 / (this.billetContainer.scaleX || 1);
          this.manualControlsContainer.setScale(invScale * (this.uiScale || 1.0));
      }

      const swX = this.UI_PAD_SIDE + 65; 
      const swY = sh - this.UI_PAD_BOTTOM - 40;
      this.toolSwitcherContainer.setPosition(swX, swY).setScale(this.uiScale || 1.0);
    };
    if (this.lastPortrait === undefined) { this.lastPortrait = nextPortrait; this.isPortrait = nextPortrait; apply(w, h, nextPortrait); return; }
    const changed = this.lastPortrait !== nextPortrait; this.lastPortrait = nextPortrait; this.isPortrait = nextPortrait;
    if (changed && !this.isRelayouting) {
      this.isRelayouting = true; const cam = this.cameras.main; cam.fadeOut(120, 0, 0, 0);
      this.time.delayedCall(140, () => {
        const ww = this.scale.gameSize.width; const hh = this.scale.gameSize.height; cam.setViewport(0, 0, ww, hh);
        apply(ww, hh, this.isPortrait); cam.fadeIn(120, 0, 0, 0);
        this.time.delayedCall(160, () => (this.isRelayouting = false));
      });
      return;
    }
    apply(w, h, nextPortrait);
  }

  private get uiScale(): number {
      return Math.min(this.viewW, this.viewH) / 720;
  }

  private repositionUI(sw: number, sh: number, portrait: boolean, isCompact: boolean) {
    if (!this.uiContainer) return;
    const padTop = this.UI_PAD_TOP; 
    const padBottom = this.UI_PAD_BOTTOM; const gap = this.UI_GAP;

    this.updateProgressBar();
    this.qualityText.setPosition(this.centerX, padTop + 45).setFontSize(isCompact ? '16px' : '18px');

    const sideAreaWidth = Math.min(sw, sh) * 0.18;
    const rightX = sw - (sideAreaWidth / 2) - this.UI_PAD_SIDE;
    const panelStartY = sh * 0.45;
    const panelEndY = sh - padBottom;

    const btnScale = sideAreaWidth / 100; 
    const btnH = 100 * btnScale;

    const heatUpY = panelEndY - (btnH / 2);
    const bellowsY = heatUpY - (btnH / 2) - gap - (btnH / 2);

    this.heatUpBtnContainer.setPosition(rightX, heatUpY).setScale(btnScale);
    this.bellowsContainer.setPosition(rightX, bellowsY).setScale(btnScale);

    const gaugeTopLimit = panelStartY + 35;
    const gaugeBottomLimit = bellowsY - (btnH / 2) - gap;
    const gaugeH = Math.max(this.TEMP_GAUGE_H_MIN, gaugeBottomLimit - gaugeTopLimit);
    const gaugeCenterY = gaugeTopLimit + (gaugeH / 2);

    this.tempValueText.setPosition(rightX, gaugeCenterY - gaugeH / 2 - 25).setFontSize(isCompact ? '12px' : '14px');

    this.refreshTempGaugeVisuals(rightX, gaugeCenterY, gaugeH);

    const infoY = portrait ? sh * 0.3 : this.centerY - (isCompact ? 80 : 140);
    this.infoText.setPosition(this.centerX, infoY).setFontSize(portrait ? (isCompact ? '20px' : '24px') : (isCompact ? '20px' : '26px'));
  }

  private refreshTempGaugeVisuals(x: number, y: number, h: number) {
      const ratio = this.temperature / 100;

      this.tempBgGraphics.clear();
      this.tempBgGraphics.fillStyle(0x1c1917, 1);
      this.tempBgGraphics.fillRoundedRect(x - 15, y - (h + 10) / 2, 30, h + 10, 15); 
      this.tempBgGraphics.lineStyle(3, 0x57534e, 1);
      this.tempBgGraphics.strokeRoundedRect(x - 15, y - (h + 10) / 2, 30, h + 10, 15);

      this.tempBgGraphics.fillStyle(0x0c0a09, 1);
      this.tempBgGraphics.fillRoundedRect(x - 11, y - h / 2, 22, h, 11);

      this.tempBarGraphics.clear();
      if (ratio > 0) {
          const barH = h * ratio;
          let barColor = 0xeab308; 
          if (ratio < 0.4) barColor = 0x3b82f6; 
          else if (ratio > 0.7) barColor = 0xef4444;

          this.tempBarGraphics.fillStyle(barColor, 1);
          this.tempBarGraphics.fillRoundedRect(x - 8, y + h / 2 - barH, 16, barH, 8); 
      }
  }

  private rebuildHitPoly() {
    const currentKey = this.billetImage?.texture?.key;
    if (!currentKey) return;
    const localPoints = this.generateOutlinePoints(currentKey);
    const rad = Phaser.Math.DegToRad(this.billetContainer.angle);
    const cos = Math.cos(rad); 
    const sin = Math.sin(rad);

    const visualScale = this.billetContainer.scaleX;
    const hitDetectionScale = visualScale * 1.1;

    const cx = this.billetContainer.x;
    const cy = this.billetContainer.y;

    const transformedHit = localPoints.map(p => ({ 
        x: cx + (p.x * hitDetectionScale * cos - p.y * hitDetectionScale * sin), 
        y: cy + (p.x * hitDetectionScale * sin + p.y * hitDetectionScale * cos) 
    }));
    this.hitPoly = new Phaser.Geom.Polygon(transformedHit);

    const transformedSpawn = localPoints.map(p => ({ 
        x: cx + (p.x * visualScale * cos - p.y * visualScale * sin), 
        y: cy + (p.x * visualScale * sin + p.y * visualScale * cos) 
    }));
    this.spawnPoly = new Phaser.Geom.Polygon(transformedSpawn);
  }

  private isPointerInHitArea(px: number, py: number) { 
      const inPoly = this.hitPoly && Phaser.Geom.Polygon.Contains(this.hitPoly, px, py);
      if (inPoly) return true;

      const distToCenter = Phaser.Math.Distance.Between(px, py, this.hitX, this.hitY);
      if (distToCenter < (this.targetRadius + 5) * this.uiScale) return true;

      return false;
  }

  private handleStartTap(x: number, y: number) {
    if (this.isReadyToStart) {
      this.isPlaying = true; this.infoText.setVisible(false);
      this.flashOverlay.setFillStyle(0xffffff, 1).setAlpha(0.2); this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 300 });
      if (this.currentTool === 'HAMMER') { this.resetRing(); this.targetRing.setVisible(true); this.approachRing.setVisible(true); }
    } else { this.cameras.main.shake(50, 0.005); this.showFeedback('TOO COLD!', 0x3b82f6, 1.0, x, y); }
  }

  private handleHammerSwing(x: number, y: number) {
    if (this.isFinished) return; if (this.time.now - this.lastHitTime < this.hitCooldown) return;
    this.lastHitTime = this.time.now;
    if (this.currentTempStage === 'COLD' || this.currentTempStage === 'NORMAL') { this.showFeedback('TOO COLD!', 0x3b82f6, 1.0, x, y); return; }
    const diff = Math.abs(this.currentRadius - this.targetRadius);
    const eff = this.currentTempStage === 'AURA' ? 1.5 : this.currentTempStage === 'HOT' ? 1.0 : 0.5;
    if (diff < this.targetRadius * 0.35) {
      this.score += Math.ceil(8 * eff); this.combo++; this.perfectCount++;
      if (this.perfectCount >= 6) { this.currentQuality += 1; }

      // --- Enhancement Logic ---
      if (this.combo > 0 && this.combo % 5 === 0) {
        this.handleEnhancement(x, y);
      }

      this.createSparks(30, this.currentTargetColor, 1.5, 'spark_perfect', x, y); this.showFeedback('PERFECT!', 0xffb300, 1.4, x, y); this.cameras.main.shake(150, 0.02);
      this.applyKickback(0.05); 
    } else if (diff < this.targetRadius * 0.95) {
      this.score += Math.ceil(5 * eff); this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 2);
      this.createSparks(15, 0xffffff, 1.1, 'spark_normal', x, y); this.showFeedback('GOOD', 0xe5e5e5, 1.1, x, y);
      this.applyKickback(0.4); 
    } else { this.handleMiss(x, y); }
    this.updateProgressBar();
    if (this.score >= this.targetScore) this.winGame(); else this.resetRing();
  }

  private handleEnhancement(x: number, y: number) {
    this.enhancementCount++;
    const pinnedText = this.add.text(x, y, '+1', {
        fontFamily: 'Grenze Gotisch',
        fontSize: '48px',
        color: '#fbbf24',
        fontStyle: 'bold',
        stroke: '#000',
        strokeThickness: 6,
        shadow: { color: '#000', fill: true, blur: 10 }
    }).setOrigin(0.5).setDepth(15).setAlpha(0).setScale(0.5);

    this.root.add(pinnedText);
    this.pinnedTexts.push(pinnedText);

    this.tweens.add({
        targets: pinnedText,
        alpha: 1,
        scale: 1,
        y: y - 20,
        duration: 400,
        ease: 'Back.out'
    });
  }

  private handleMiss(x?: number, y?: number, customText?: string) {
    this.score = Math.max(0, this.score - 5); this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.cameras.main.shake(100, 0.01); this.showFeedback(customText ?? 'MISS', 0xef4444, 1.0, x ?? this.hitX, y ?? this.hitY);
    this.applyKickback(1.5); 
    this.updateProgressBar(); this.resetRing();
  }

  update(time: number, delta: number) {
    if (this.isFinished) return;
    if (this.isPlaying && this.currentTool === 'HAMMER') this.handleRingLogic(delta);
    this.temperature = Math.max(0, this.temperature - this.coolingRate * (delta / 1000));
    this.refreshVisuals();
    if (!this.isPlaying && this.isReadyToStart && this.temperature <= 0) {
      this.isReadyToStart = false; this.infoText.setText('FORGE IS COLD\nADD FUEL').setColor('#3b82f6');
    }
  }

  private refreshVisuals() {
    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    const ratio = this.temperature / 100;
    this.tempValueText.setText(`${Math.floor(20 + ratio * 1480)}°C`);

    if (this.tempBarGraphics) {
        const sideAreaWidth = Math.min(this.viewW, this.viewH) * 0.18;
        const rightX = this.viewW - (sideAreaWidth / 2) - this.UI_PAD_SIDE;
        const panelStartY = this.viewH * 0.45;
        const btnScale = sideAreaWidth / 100;
        const btnH = 100 * btnScale;
        const heatUpY = (this.viewH - this.UI_PAD_BOTTOM) - (btnH / 2);
        const bellowsY = heatUpY - (btnH / 2) - this.UI_GAP - (btnH / 2);
        const gaugeTopLimit = panelStartY + 35;
        const gaugeBottomLimit = bellowsY - (btnH / 2) - this.UI_GAP;
        const gaugeH = Math.max(this.TEMP_GAUGE_H_MIN, gaugeBottomLimit - gaugeTopLimit);
        const gaugeCenterY = gaugeTopLimit + (gaugeH / 2);
        this.refreshTempGaugeVisuals(rightX, gaugeCenterY, gaugeH);
    }

    const progress = Phaser.Math.Clamp(this.score / this.targetScore, 0, 1);
    const stage = Math.min(5, Math.floor(progress * 6)); 
    this.setBilletStage(stage);
    if (this.ambientGlow) this.ambientGlow.setAlpha(ratio * 0.4);
    if (this.temperature <= 0) this.currentTempStage = 'COLD';
    else if (this.temperature > 75) this.currentTempStage = 'AURA';
    else if (this.temperature > 40) this.currentTempStage = 'HOT';
    else if (this.temperature > 15) this.currentTempStage = 'WARM';
    else this.currentTempStage = 'NORMAL';
  }

  private setBilletStage(stage: number) {
    const key = `blade_stage_${stage}`; if (stage === 0) { if (this.billetImage) this.billetImage.setTexture('billet_stage_0'); this.placeBilletOnAnvil(); return; }
    if (!this.textures.exists(key)) return;
    if (!this.billetImage) { 
        this.billetImage = this.add.image(0, 0, key).setOrigin(0.5); 
        this.billetContainer.add(this.billetImage); 
        this.placeBilletOnAnvil(); 
        return; 
    }
    if (this.billetImage.texture.key !== key) {
      this.billetImage.setTexture(key); 
      this.placeBilletOnAnvil();
      const sx = this.billetContainer.scaleX; const sy = this.billetContainer.scaleY;
      this.tweens.add({ targets: this.billetContainer, scaleX: sx * 1.08, scaleY: sy * 1.08, duration: 100, yoyo: true, });
    }
  }

  private handleRingLogic(delta: number) {
    this.ringTimer += delta * this.currentSpeedMult; 
    const t = Math.min(this.ringTimer / this.shrinkDuration, 1.5); 
    this.currentRadius = this.startRadius * (1 - t * t);
    const colorT = Math.min(this.ringTimer / this.shrinkDuration, 1.0);
    const targetRGB = Phaser.Display.Color.IntegerToColor(this.currentTargetColor);
    const r = Math.floor(255 + (targetRGB.red - 255) * colorT);
    const g = Math.floor(255 + (targetRGB.green - 255) * colorT);
    const b = Math.floor(255 + (targetRGB.blue - 255) * colorT);
    const ringColor = Phaser.Display.Color.GetColor(r, g, b);
    const ringAlpha = 0.6 + (colorT * 0.3);

    this.approachRing.clear()
        .lineStyle(6, ringColor, ringAlpha)
        .fillStyle(ringColor, ringAlpha * 0.15) 
        .fillCircle(this.hitX, this.hitY, Math.max(0, this.currentRadius))
        .strokeCircle(this.hitX, this.hitY, Math.max(0, this.currentRadius));

    if (this.currentRadius < this.targetRadius - 25) { this.combo = 0; this.resetRing(); }
  }

  private resetRing() {
    if (this.temperature <= 0 || !this.spawnPoly) return; 
    this.targetRing.clear(); 
    this.approachRing.clear(); 
    this.currentRadius = this.startRadius; 
    this.ringTimer = 0;
    const randType = Math.random();
    if (randType < 0.2) { this.currentTargetColor = 0x10b981; this.currentSpeedMult = 0.75; } 
    else if (randType < 0.75) { this.currentTargetColor = 0xfabf24; this.currentSpeedMult = 1.0; } 
    else { this.currentTargetColor = 0xef4444; this.currentSpeedMult = 1.45; }
    this.targetRadius = this.startRadius * Phaser.Math.FloatBetween(0.18, 0.32);

    const rect = Phaser.Geom.Polygon.GetAABB(this.spawnPoly);
    let found = false; let attempts = 0;
    while (!found && attempts < 20) {
        const tx = Phaser.Math.FloatBetween(rect.left, rect.right);
        const ty = Phaser.Math.FloatBetween(rect.top, rect.bottom);
        if (Phaser.Geom.Polygon.Contains(this.spawnPoly, tx, ty)) { this.hitX = tx; this.hitY = ty; found = true; }
        attempts++;
    }

    if (this.isPlaying && this.currentTool === 'HAMMER') { 
      this.targetRing.clear()
        .fillStyle(this.currentTargetColor, 0.25)
        .fillCircle(this.hitX, this.hitY, this.targetRadius)
        .lineStyle(4, this.currentTargetColor, 0.7)
        .strokeCircle(this.hitX, this.hitY, this.targetRadius); 
    }
  }

  private updateProgressBar() {
    if (!this.progBg || !this.progressBar) return;
    const progWidth = Math.min(this.viewW * (this.isPortrait ? 0.72 : 0.6), 340);
    const progX = this.centerX - progWidth / 2;
    const padTop = this.UI_PAD_TOP + 10;

    this.progBg.clear();
    this.progBg.fillStyle(0x1c1917, 1);
    this.progBg.fillRoundedRect(progX, padTop, progWidth, 18, 9); 
    this.progBg.lineStyle(2, 0x57534e, 1);
    this.progBg.strokeRoundedRect(progX, padTop, progWidth, 18, 9);

    this.progressBar.clear();
    const ratio = Phaser.Math.Clamp(this.score / this.targetScore, 0, 1);
    if (ratio > 0) {
        this.progressBar.fillStyle(0xeab308, 1);
        this.progressBar.fillRoundedRect(progX + 2, padTop + 2, (progWidth - 4) * ratio, 14, 7); 
    }
  }

  private createSparks(count: number, color: number, scale: number, key: string, x: number, y: number) {
    const emitter = this.add.particles(x, y, this.textures.exists(key) ? key : 'spark_normal', { lifespan: 600, speed: { min: 200 * scale, max: 500 * scale }, angle: { min: 230, max: 310 }, scale: { start: 0.6, end: 0 }, gravityY: 1000, blendMode: 'ADD', tint: color, });
    this.root.add(emitter); emitter.explode(count);
  }

  private showFeedback(text: string, color: number, scale: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: '32px', fontStyle: 'bold', color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 7, }).setOrigin(0.5).setScale(0.5).setAlpha(0).setDepth(25);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 1, scale: scale, duration: 250, hold: 400, yoyo: true, onComplete: () => fb.destroy(), });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 75).setText(`${this.combo} COMBO!`).setAlpha(1).setScale(1.2); this.tweens.add({ targets: this.comboText, scale: { from: 1.4, to: 1 }, duration: 200, alpha: { from: 1, to: 0 }, delay: 700, }); }
  }

  private winGame() {
    this.isFinished = true; this.isPlaying = false; this.targetRing.clear(); this.approachRing.clear();
    if (this.manualControlsContainer) this.manualControlsContainer.setVisible(false);
    if (this.toolSwitcherContainer) this.toolSwitcherContainer.setVisible(false);
    if (this.onStatusUpdate) this.onStatusUpdate(this.temperature);
    const bg = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(bg); this.tweens.add({ targets: bg, alpha: 0.8, duration: 500 });
    const label = this.getQualityLabel(this.currentQuality);
    const textContent = this.isPortrait ? `${label}\nCRAFT!` : `${label} CRAFT!`;
    const fontSize = this.isPortrait ? `${Math.min(36, this.viewW * 0.08)}px` : '48px';
    const txt = this.add.text(this.centerX, this.centerY, textContent, { fontFamily: 'Grenze Gotisch', fontSize: fontSize, color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 4, align: 'center', }).setOrigin(0.5).setAlpha(0).setDepth(101);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: { from: 0.5, to: this.isPortrait ? 1.0 : 1.1 }, duration: 600, ease: 'Back.out', onComplete: () => { this.time.delayedCall(1000, () => { if (this.onComplete) this.onComplete(this.currentQuality, this.enhancementCount); }); }, });
  }

  private pumpBellows() {
    this.isPumping = true; 
    this.bellowsSprite.play('bellows_pump', true); 

    this.tweens.add({
        targets: this.bellowsBg,
        alpha: { from: 1, to: 0.7 },
        scale: { from: 1, to: 1.1 },
        duration: 150,
        yoyo: true,
        ease: 'Cubic.out'
    });

    if (this.temperature > 0) { this.temperature = Math.min(100, this.temperature + 5); if (!this.isPlaying && !this.isReadyToStart) { this.isReadyToStart = true; this.infoText.setText('TOUCH TO START').setColor('#fbbf24'); } }
  }

  private requestHeatUp() { 
    const hasCharcoal = this.charcoalCount === '∞' || (typeof this.charcoalCount === 'number' && this.charcoalCount > 0);
    if (hasCharcoal && this.onHeatUpRequest) { this.tweens.add({ targets: this.heatUpBtnContainer, scale: 0.9, duration: 50, yoyo: true }); this.onHeatUpRequest(); } else { this.cameras.main.shake(100, 0.005); } 
  }

  public heatUp() { this.temperature = Math.min(100, this.temperature + 40); if (!this.isPlaying) { this.isReadyToStart = true; this.infoText.setText('TOUCH TO START').setColor('#fbbf24'); } this.flashOverlay.setFillStyle(0xff8800, 1).setAlpha(0.4); this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 400, ease: 'Cubic.easeOut' }); }
  public updateCharcoalCount(count: number | string) { this.charcoalCount = count; this.refreshHeatUpButton(); }
  private refreshHeatUpButton() { 
    const bg = this.heatUpBtnContainer.getByName('btnBg') as Phaser.GameObjects.Arc; 
    const countTxt = this.heatUpBtnContainer.getByName('countTxt') as Phaser.GameObjects.Text; 
    if (countTxt) countTxt.setText(`x${this.charcoalCount}`); 
    const hasCharcoal = this.charcoalCount === '∞' || (typeof this.charcoalCount === 'number' && this.charcoalCount > 0);
    if (bg) bg.setStrokeStyle(3, hasCharcoal ? 0xea580c : 0x292524); 
  }
  public getTemperature() { return this.temperature; }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

type RingType = 'NARROW' | 'MEDIUM' | 'WIDE';

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        
  endP?: number;    
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; 
  totalTicksInRange: number; 
  graphic?: Phaser.GameObjects.Arc; 
  nailHead?: Phaser.GameObjects.Image; 
  tracedSegments?: { start: number; end: number }[]; 
  startHit?: boolean; 
  startHitPerfect?: boolean; 
  missedStart?: boolean; 
  ringType?: RingType;   
}

function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Container;
  private cursorSprite!: Phaser.GameObjects.Image;
  private cursorBar!: Phaser.GameObjects.Rectangle;
  private hammerSprite!: Phaser.GameObjects.Image;

  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00012; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private enhancementCount = 0; // 강화 횟수
  private isFinished = false;
  private isTransitioning = false; 
  private currentPhase = 1;

  private onComplete?: (score: number, enhancementCount: number) => void;
  private itemImage: string = '';
  private subCategoryId: string = '';
  private difficulty: number = 1;
  private isLeatherWork: boolean = false;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.subCategoryId = data.subCategoryId || '';

    const leatherCategories = ['CHESTPLATE', 'GLOVES', 'BOOTS'];
    this.isLeatherWork = leatherCategories.includes(this.subCategoryId.toUpperCase());

    this.cursorSpeed = 0.00012 + data.difficulty * 0.000020; 
    this.isFinished = false;
    this.isTransitioning = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.enhancementCount = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('nail', getAssetUrl('nail.png'));
    this.load.image('nail_head', getAssetUrl('nail_head.png'));
    this.load.image('hammer', getAssetUrl('hammer.png'));
    this.load.image('saw', getAssetUrl('saw.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  private getRingColor(type?: RingType): number {
    if (type === 'NARROW') return 0x22d3ee; 
    if (type === 'WIDE') return 0xa855f7;   
    return 0x10b981;                        
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    this.cursor = this.add.container(0, 0).setDepth(10);
    this.cursorSprite = this.add.image(0, 0, 'niddle').setOrigin(0.5, 0.98).setScale(0.4);
    this.cursorBar = this.add.rectangle(0, 0, 6, 40, 0xfbbf24).setOrigin(0.5, 1).setStrokeStyle(2, 0xffffff, 0.8);
    this.cursor.add([this.cursorBar, this.cursorSprite]);
    this.root.add(this.cursor);

    this.hammerSprite = this.add.image(0, 0, 'hammer').setOrigin(0.5, 0.9).setScale(0.35).setAlpha(0).setDepth(25);
    this.root.add(this.hammerSprite);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished || this.isTransitioning) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        const nodePos = this.getPathPosition(obj.p);
        const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
        const diff = Math.abs(this.cursorProgress - obj.p);

        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          let tapHitRadius = 42; 
          if (obj.ringType === 'NARROW') tapHitRadius = 26;
          else if (obj.ringType === 'MEDIUM') tapHitRadius = 42;
          else if (obj.ringType === 'WIDE') tapHitRadius = 62;

          if (d < tapHitRadius * this.uiScale) {
            this.handleTapHit(i, nodePos.x, nodePos.y);
            break;
          }
        }

        if (obj.type === 'DRAG' && !obj.hit && !obj.missed && !obj.startHit) {
            let hitRadius = 42;
            if (obj.ringType === 'NARROW') hitRadius = 26;
            else if (obj.ringType === 'MEDIUM') hitRadius = 42;
            else if (obj.ringType === 'WIDE') hitRadius = 62;

            if (d < hitRadius * this.uiScale && diff < 0.08) {
                obj.startHit = true;
                obj.missedStart = false;
                const perfectThreshold = obj.ringType === 'NARROW' ? 0.025 : 0.035;
                obj.startHitPerfect = diff < perfectThreshold; 
                obj.tracedSegments = [{ start: obj.p, end: this.cursorProgress }];
                const label = obj.startHitPerfect ? 'PERFECT!' : 'GOOD';
                const color = obj.startHitPerfect ? 0xfbbf24 : this.getRingColor(obj.ringType);
                this.showFeedback(label, color, nodePos.x, nodePos.y);
                this.createSparks(nodePos.x, nodePos.y, color, obj.startHitPerfect ? 10 : 5);

                if (obj.startHitPerfect) {
                  this.combo++;
                  if (this.combo > 0 && this.combo % 5 === 0) {
                    this.handleEnhancement(nodePos.x, nodePos.y);
                  }
                } else {
                  this.combo = 0;
                }
                break;
            }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.isTransitioning = false;
    this.updateCursorTool();
    this.spawnInteractablesForPhase();

    const pos = this.getPathPosition(0);
    this.cursor.setPosition(pos.x, pos.y);
  }

  private updateCursorTool() {
    if (!this.cursor) return;
    this.hammerSprite.setAlpha(0);
    if (this.isLeatherWork) {
        this.cursorSprite.setVisible(true).setTexture('niddle').setOrigin(0.5, 0.98).setScale(0.4);
        this.cursorBar.setVisible(false);
    } else {
        if (this.currentPhase === 1 || this.currentPhase === 3) {
            this.cursorSprite.setVisible(false);
            this.cursorBar.setVisible(true).setFillStyle(0xfbbf24).setAlpha(1);
        } else {
            this.cursorSprite.setVisible(true).setTexture('saw').setOrigin(0.05, 0.5).setScale(0.45);
            this.cursorBar.setVisible(false);
        }
    }
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;
    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);
            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }
            if (!obj.startHit && !obj.hit) {
                const startPos = this.getPathPosition(obj.p);
                const ringColor = this.getRingColor(obj.ringType);
                let ringRadius = 20; let strokeW = 4; let alpha = 1;
                if (obj.ringType === 'NARROW') { ringRadius = 12; strokeW = 5; alpha = 1.0; }
                else if (obj.ringType === 'MEDIUM') { ringRadius = 20; strokeW = 4; alpha = 0.8; }
                else if (obj.ringType === 'WIDE') { ringRadius = 30; strokeW = 3; alpha = 0.6; }
                this.dragPathGraphics.lineStyle(strokeW, ringColor, alpha).strokeCircle(startPos.x, startPos.y, ringRadius * this.uiScale);
                this.dragPathGraphics.fillStyle(ringColor, alpha * 0.4).fillCircle(startPos.x, startPos.y, (ringRadius - 6) * this.uiScale);
            }
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const stepDistancePx = 4;
    const segmentLengthP = endP - startP;
    const segmentLengthPx = segmentLengthP * this.totalPathLength;
    const steps = Math.max(2, Math.ceil(segmentLengthPx / stepDistancePx));
    const stepSizeP = segmentLengthP / steps;
    const firstPos = this.getPathPosition(startP); 
    graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { 
        const currentP = startP + stepSizeP * i;
        const pos = this.getPathPosition(currentP); 
        graphics.lineTo(pos.x, pos.y); 
    }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => {
        obj.graphic?.destroy();
        obj.nailHead?.destroy();
    });
    this.interactables = [];
    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }
    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const types: RingType[] = ['NARROW', 'MEDIUM', 'WIDE'];
    const ringType = types[Math.floor(Math.random() * types.length)];
    const ringColor = this.getRingColor(ringType);
    let ringRadius = 20;
    if (ringType === 'NARROW') ringRadius = 12;
    else if (ringType === 'MEDIUM') ringRadius = 20;
    else if (ringType === 'WIDE') ringRadius = 30;

    const pos = this.getPathPosition(p);
    const node = this.add.circle(pos.x, pos.y, ringRadius * this.uiScale, ringColor, 0.3).setStrokeStyle(3, ringColor).setDepth(8);

    let nailHead: Phaser.GameObjects.Image | undefined;
    if (!this.isLeatherWork) {
        const targetSize = ringRadius * 2 * this.uiScale;
        nailHead = this.add.image(pos.x, pos.y, 'nail_head').setDepth(7).setDisplaySize(targetSize, targetSize);
        this.root.add(nailHead);
    }

    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node, nailHead, ringType });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    const ringType: RingType = 'MEDIUM';
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [], startHit: false, startHitPerfect: false, missedStart: false, ringType });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      const pos = this.getPathPosition(obj.p);
      if (obj.type === 'TAP' && !obj.missed) {
        let ringRadius = 20;
        if (obj.ringType === 'NARROW') ringRadius = 12;
        else if (obj.ringType === 'MEDIUM') ringRadius = 20;
        else if (obj.ringType === 'WIDE') ringRadius = 30;

        if (obj.graphic) {
            obj.graphic.setPosition(pos.x, pos.y).setRadius(ringRadius * this.uiScale);
        }
        if (obj.nailHead) {
            const targetSize = ringRadius * 2 * this.uiScale;
            const finalSize = targetSize * (obj.hit ? 0.8 : 1);
            obj.nailHead.setPosition(pos.x, pos.y).setDisplaySize(finalSize, finalSize);
        }
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.isTransitioning || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;
    this.interactables.forEach((obj) => {
      if (!obj.hit && !obj.missed) {
          if (this.cursorProgress > obj.p + 0.1) {
              if (obj.type === 'TAP') {
                  obj.missed = true;
                  const pos = this.getPathPosition(obj.p);
                  this.handleMiss(pos.x, pos.y, obj);
              } else if (obj.type === 'DRAG' && !obj.startHit && !obj.missedStart) {
                  obj.missedStart = true;
              }
          }
      }
    });
    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();
    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    const isSaw = !this.isLeatherWork && (this.currentPhase === 2 || this.currentPhase === 4);
    const rotationOffset = isSaw ? 0 : -Math.PI / 2;
    const targetRotation = pos.angle + rotationOffset;

    const angleDelta = Phaser.Math.Angle.ShortestBetween(Phaser.Math.RadToDeg(this.cursor.rotation), Phaser.Math.RadToDeg(targetRotation));
    this.cursor.angle += angleDelta * 0.15;

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);

            if (pointer.isDown && dist < 60 * this.uiScale) {
                if (!obj.startHit) {
                    obj.startHit = true;
                    if (!obj.tracedSegments) obj.tracedSegments = [];
                    obj.tracedSegments.push({ start: p, end: p });
                }
                obj.dragSuccessTicks += delta; 
                this.dragPenaltyTimer = 0; 
                if (this.cursorSprite.visible) this.cursorSprite.setTint(0xfbbf24);
                if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfcd34d);

                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) { lastSeg.end = p; } 
                else { obj.tracedSegments.push({ start: p, end: p }); }
            } else if (obj.startHit) {
                this.dragPenaltyTimer += delta; 
                this.cursorSprite.clearTint();
                if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfbbf24);

                if (this.dragPenaltyTimer > 150) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.2);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(40, 0.001);
                }
            } else { 
                this.cursorSprite.clearTint(); 
                if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfbbf24);
            }
        }
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.92 && obj.startHitPerfect && !obj.missedStart) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 3.0);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.60) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 1.0);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else { obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y); }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) {
        this.cursorSprite.clearTint();
        if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfbbf24);
    }
  }

  private handleTapHit(idx: number, targetX: number, targetY: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);

    if (diff < 0.07) {
      obj.hit = true;
      const isPerfect = diff < 0.03;
      const ringColor = this.getRingColor(obj.ringType);

      if (!this.isLeatherWork) {
          this.hammerSprite
              .setAlpha(1)
              .setPosition(targetX + 40, targetY - 120)
              .setAngle(5);

          this.tweens.add({
              targets: this.hammerSprite,
              x: targetX,
              y: targetY + 20, 
              angle: -30,
              duration: 100,
              ease: 'Cubic.in',
              onComplete: () => {
                  this.tweens.add({
                      targets: this.hammerSprite,
                      angle: -10,
                      y: targetY + 10,
                      alpha: 0,
                      duration: 250,
                      ease: 'Cubic.out'
                  });
              }
          });
      }

      if (obj.nailHead) {
          this.tweens.add({
              targets: obj.nailHead,
              displayWidth: obj.nailHead.displayWidth * 0.8,
              displayHeight: obj.nailHead.displayHeight * 0.8,
              duration: 100,
              ease: 'Back.easeOut'
          });
      }

      if (isPerfect) {
        this.combo++;
        this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);

        // --- Enhancement Logic ---
        if (this.combo > 0 && this.combo % 5 === 0) {
            this.handleEnhancement(pos.x, pos.y);
        }
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.5);
        this.showFeedback('GOOD', ringColor, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, ringColor, 8);
      }

      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() });
      }
    }
  }

  private handleEnhancement(x: number, y: number) {
    this.enhancementCount++;
    const pinnedText = this.add.text(x, y, '+1', {
        fontFamily: 'Grenze Gotisch',
        fontSize: '48px',
        color: '#fbbf24',
        fontStyle: 'bold',
        stroke: '#000',
        strokeThickness: 6,
        shadow: { color: '#000', fill: true, blur: 10 }
    }).setOrigin(0.5).setDepth(15).setAlpha(0).setScale(0.5);

    this.root.add(pinnedText);

    this.tweens.add({
        targets: pinnedText,
        alpha: 1,
        scale: 1,
        y: y - 20,
        duration: 400,
        ease: 'Back.out'
    });
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 6);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(120, 0.005);

    if (obj?.graphic) { this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() }); }
    if (obj?.nailHead) { this.tweens.add({ targets: obj.nailHead, alpha: 0, duration: 200, onComplete: () => obj.nailHead?.destroy() }); }
  }

  private finishPhase() {
    this.isTransitioning = true; 
    this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); 
    this.updateProgressBar();

    this.interactables.forEach(obj => {
        if (obj.graphic) this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 400 });
        if (obj.nailHead) this.tweens.add({ targets: obj.nailHead, alpha: 0, duration: 400 });
    });

    const isLastPhase = this.currentPhase >= 4;
    const splashText = isLastPhase ? 'WORK COMPLETE!' : `PHASE ${this.currentPhase} COMPLETE!`;
    const splashColor = isLastPhase ? '#fbbf24' : '#10b981';

    const splash = this.add.text(this.centerX, this.centerY, splashText, {
        fontFamily: 'Grenze Gotisch',
        fontSize: '48px',
        color: splashColor,
        stroke: '#000',
        strokeThickness: 8
    }).setOrigin(0.5).setAlpha(0).setScale(0.5).setDepth(100);

    this.root.add(splash);

    this.tweens.chain({
        targets: splash,
        tweens: [
            { alpha: 1, scale: 1.2, duration: 400, ease: 'Back.out' },
            { scale: 1, duration: 800 },
            { alpha: 0, scale: 1.5, duration: 300, ease: 'Cubic.in' }
        ],
        onComplete: () => {
            splash.destroy();
            if (isLastPhase) {
                this.win();
            } else {
                this.time.delayedCall(500, () => {
                    this.startPhase(this.currentPhase + 1);
                });
            }
        }
    });
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality, this.enhancementCount); });
    }});
  }
}

import { EquipmentItem } from '../types/inventory';
import { Equipment, EquipmentRarity, EquipmentType, EquipmentStats } from '../models/Equipment';
import { MASTERY_THRESHOLDS } from '../config/mastery-config';

const mapSubCategoryToType = (subCat: string): EquipmentType => {
    return subCat as EquipmentType; 
};

export const getEnergyCost = (item: EquipmentItem, masteryCount: number): number => {
    let cost = 20; 
    if (masteryCount >= MASTERY_THRESHOLDS.ARTISAN) {
        cost -= MASTERY_THRESHOLDS.ARTISAN_BONUS.energyDiscount;
    }
    return Math.max(5, cost);
};

export const generateEquipment = (recipe: EquipmentItem, quality: number, masteryCount: number, enhancementCount: number = 0): Equipment => {
    let statMultiplier = 1.0;
    let priceMultiplier = 1.0;
    let namePrefix = '';

    if (masteryCount >= MASTERY_THRESHOLDS.ARTISAN) {
        statMultiplier = MASTERY_THRESHOLDS.ARTISAN_BONUS.stats;
        priceMultiplier = MASTERY_THRESHOLDS.ARTISAN_BONUS.price;
        namePrefix = MASTERY_THRESHOLDS.ARTISAN_BONUS.prefix;
    } else if (masteryCount >= MASTERY_THRESHOLDS.ADEPT) {
        statMultiplier = MASTERY_THRESHOLDS.ADEPT_BONUS.stats;
        priceMultiplier = MASTERY_THRESHOLDS.ADEPT_BONUS.price;
        namePrefix = MASTERY_THRESHOLDS.ADEPT_BONUS.prefix;
    }

    const qualityMultiplier = Math.max(0.2, quality / 100); 
    const finalMultiplier = qualityMultiplier * statMultiplier;

    const base = recipe.baseStats || { physicalAttack: 0, physicalDefense: 0, magicalAttack: 0, magicalDefense: 0 };

    const stats: EquipmentStats = {
        physicalAttack: Math.round(base.physicalAttack * finalMultiplier),
        physicalDefense: Math.round(base.physicalDefense * finalMultiplier),
        magicalAttack: Math.round(base.magicalAttack * finalMultiplier),
        magicalDefense: Math.round(base.magicalDefense * finalMultiplier),
    };

    // --- ENHANCEMENT LOGIC ---
    // Every +1 grants a 2% boost to a random relevant stat
    const statKeys: (keyof EquipmentStats)[] = ['physicalAttack', 'physicalDefense', 'magicalAttack', 'magicalDefense'];
    for (let i = 0; i < enhancementCount; i++) {
        const randomKey = statKeys[Math.floor(Math.random() * statKeys.length)];
        stats[randomKey] = Math.round(stats[randomKey] * 1.02);
    }

    // Rarity determination based on Quality + Enhancement intensity
    const rarityScore = quality + (enhancementCount * 2);

    let rarity = EquipmentRarity.COMMON;
    if (rarityScore >= 125) rarity = EquipmentRarity.LEGENDARY; 
    else if (rarityScore >= 110) rarity = EquipmentRarity.EPIC;  
    else if (rarityScore >= 95) rarity = EquipmentRarity.RARE;
    else if (rarityScore >= 75) rarity = EquipmentRarity.UNCOMMON;

    const price = Math.round(recipe.baseValue * finalMultiplier * priceMultiplier * (1 + enhancementCount * 0.05));

    return {
        id: `${recipe.id}_${Date.now()}_${Math.floor(Math.random() * 1000)}`,
        recipeId: recipe.id,
        name: namePrefix ? `${namePrefix} ${recipe.name}` : recipe.name,
        type: mapSubCategoryToType(recipe.subCategoryId),
        quality: quality,
        rarity: rarity,
        price: price,
        icon: recipe.icon,
        image: recipe.image,
        description: recipe.description,
        stats: stats,
        enhancementCount,
        specialAbilities: [], 
        durability: recipe.maxDurability, 
        maxDurability: recipe.maxDurability,
        isRepairable: recipe.isRepairable,
        equipRequirements: recipe.equipRequirements,
        craftedDate: Date.now(),
        previousOwners: [], 
        slotType: recipe.slotType,
        isTwoHanded: recipe.isTwoHanded
    };
};

import { GameState, InventoryItem } from '../../types/index';
import { EquipmentItem } from '../../types/inventory';
import { getEnergyCost, generateEquipment } from '../../utils/craftingLogic';
import { MATERIALS } from '../../data/materials';

const getQualityLabel = (q: number): string => {
    if (q >= 110) return "MASTERWORK";
    if (q >= 100) return "PRISTINE";
    if (q >= 90) return "SUPERIOR";
    if (q >= 80) return "FINE";
    if (q >= 70) return "STANDARD";
    if (q >= 60) return "RUSTIC";
    return "CRUDE";
};

export const handleStartCrafting = (state: GameState, payload: { item: EquipmentItem }): GameState => {
    const { item } = payload;
    const masteryCount = state.craftingMastery[item.id] || 0;
    const energyCost = getEnergyCost(item, masteryCount);

    if (state.stats.energy < energyCost) return state;

    const hasResources = item.requirements.every(req => {
        const invItem = state.inventory.find(i => i.id === req.id);
        return invItem && invItem.quantity >= req.count;
    });
    if (!hasResources) return state;

    let newInventory = [...state.inventory];
    item.requirements.forEach(req => {
        newInventory = newInventory.map(invItem => {
            if (invItem.id === req.id) {
                return { ...invItem, quantity: invItem.quantity - req.count };
            }
            return invItem;
        }).filter(i => i.quantity > 0);
    });

    return {
        ...state,
        isCrafting: true,
        stats: { ...state.stats, energy: state.stats.energy - energyCost },
        inventory: newInventory,
    };
};

export const handleCancelCrafting = (state: GameState, payload: { item: EquipmentItem }): GameState => {
    const { item } = payload;
    const masteryCount = state.craftingMastery[item.id] || 0;
    const energyCost = getEnergyCost(item, masteryCount);

    let newInventory = [...state.inventory];
    item.requirements.forEach(req => {
        const existing = newInventory.find(i => i.id === req.id);
        if (existing) {
            newInventory = newInventory.map(i => i.id === req.id ? { ...i, quantity: i.quantity + req.count } : i);
        } else {
            const itemDef = Object.values(MATERIALS).find(m => m.id === req.id);
            if (itemDef) {
                newInventory.push({ ...itemDef, quantity: req.count } as InventoryItem);
            }
        }
    });

    return {
        ...state,
        isCrafting: false,
        stats: { ...state.stats, energy: state.stats.energy + energyCost },
        inventory: newInventory,
        logs: [`Cancelled work on ${item.name}. Materials restored.`, ...state.logs]
    };
};

export const handleFinishCrafting = (state: GameState, payload: { item: EquipmentItem; quality: number; bonus?: number; masteryGain?: number }): GameState => {
    const { item, quality, bonus = 0, masteryGain = 1 } = payload;
    const masteryCount = state.craftingMastery[item.id] || 0;

    // 'bonus' parameter is used as enhancementCount
    const equipment = generateEquipment(item, quality, masteryCount, bonus);

    const newItem: InventoryItem = {
        id: equipment.id, 
        name: equipment.name,
        type: 'EQUIPMENT',
        description: item.description,
        baseValue: equipment.price,
        icon: item.icon,
        quantity: 1,
        equipmentData: equipment
    };

    const newInventory = [...state.inventory, newItem];

    const newMastery = { ...state.craftingMastery };
    newMastery[item.id] = (masteryCount || 0) + masteryGain;

    const label = getQualityLabel(quality);
    let logMsg = `Successfully crafted ${label.toLowerCase()} quality ${item.name}!`;
    if (bonus > 0) logMsg += ` Pinned technique applied +${bonus} enhancements.`;

    let newUnlockedTabs = [...state.unlockedTabs];
    if (!newUnlockedTabs.includes('INVENTORY')) {
        newUnlockedTabs.push('INVENTORY');
        logMsg = "Facility restored: Inventory tracking is now active. " + logMsg;
    }

    return {
        ...state,
        isCrafting: false,
        inventory: newInventory,
        unlockedTabs: newUnlockedTabs,
        craftingMastery: newMastery,
        lastCraftedItem: newItem, 
        logs: [logMsg, ...state.logs]
    };
};

export const handleSetCrafting = (state: GameState, isCrafting: boolean): GameState => {
    return { ...state, isCrafting };
};

export const handleUpdateForgeStatus = (state: GameState, payload: { temp: number }): GameState => {
    return {
        ...state,
        forgeTemperature: payload.temp,
        lastForgeTime: Date.now()
    };
};

